def canonical_kind(kind: str) -> str:
    """Return the canonical wire spelling for *kind*.

    Identity for any kind not in the registry (the overwhelming common
    case: the kind is already canonical). The registry only records the
    alias collapses that exist today (e.g. the floordiv family)."""
    return CANONICAL_KIND.get(kind, kind)
